#include <stdio.h>
#include <string.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    char s[100005];
    while(T--){
        scanf("%s", s);
        int n = strlen(s);
        // build reverse on the fly using two pointers
        int j = 0; // index in reversed string
        // we will compare s[i] with rev[j] which is s[n-1-j]
        for(int i=0;i<n;i++){
            if(s[i]==s[n-1-j]) j++;
            if(j==n) break;
        }
        printf("%d\n", n - j);
    }
    return 0;
}

