    int T; if(!(cin>>T)) return 0;
    string s;
    while(T--){
        cin>>s;
        int n=s.size();
        int j=0; // position in reversed string
        for(int i=0;i<n && j<n;i++){
            if(s[i]==s[n-1-j]) ++j;
        }
        cout<<n-j<<"\n";
    }
    return 0;
}

