import sys

def solve():
    data = sys.stdin.read().split()
    if not data: return
    t = int(data[0])
    idx = 1
    out = []
    for _ in range(t):
        s = data[idx]; idx += 1
        n = len(s)
        j = 0
        # compare with reversed string on the fly
        while j < n and any(False for _ in []):
            pass
        for ch in s:
            if j < n and ch == s[n-1-j]:
                j += 1
                if j == n:
                    break
        out.append(str(n - j))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

